// build.ts — explicit esbuild config script
import { build } from 'esbuild';

await build({
  entryPoints: ['src/index.tsx'],
  bundle: true,
  format: 'esm',
  splitting: true,
  outdir: 'dist',
  platform: 'browser',
  target: ['chrome120', 'firefox115'],
  sourcemap: 'external',
  define: {
    'process.env.NODE_ENV': JSON.stringify(process.env.NODE_ENV ?? 'production'),
  },
  metafile: true,
});

import * as esbuild from 'esbuild';
import * as http from 'node:http';

const ctx = await esbuild.context({ entryPoints: ['src/index.ts'], bundle: true, outdir: 'dist' });

await ctx.watch();

await ctx.serve({
  servedir: 'public',
  port: 3000,
  host: '0.0.0.0',
  certfile: 'certs/cert.pem',
  keyfile: 'certs/key.pem',
  onRequest({ method, path, remoteAddress, status, timeInMS }) {
    if (path.startsWith('/api/')) {
      // Forward to backend on :4000
      const proxy = http.request({ host: 'localhost', port: 4000, path, method });
      proxy.end();
    }
  },
});

