import * as esbuild from 'esbuild';
import { gzipSync, brotliCompressSync } from 'zlib';
import { writeFileSync } from 'fs';

const result = await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  format: 'esm',
  minify: true,        // minifyWhitespace + minifyIdentifiers + minifySyntax
  treeShaking: true,
  metafile: true,
  write: false,        // capture buffers in memory
});

for (const file of result.outputFiles) {
  writeFileSync(file.path, file.contents);
  writeFileSync(`${file.path}.gz`, gzipSync(file.contents, { level: 9 }));
  writeFileSync(`${file.path}.br`, brotliCompressSync(file.contents));
}

console.log(await esbuild.analyzeMetafile(result.metafile));

import * as esbuild from 'esbuild';

const virtualPlugin: esbuild.Plugin = {
  name: 'virtual-env',
  setup(build) {
    build.onResolve({ filter: /^env$/ }, () => ({
      path: 'env',
      namespace: 'virtual-env-ns',
    }));

    build.onLoad({ filter: /.*/, namespace: 'virtual-env-ns' }, () => ({
      contents: `export const MODE = '${process.env.NODE_ENV}';`,
      loader: 'js',
    }));
  },
};

await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  plugins: [virtualPlugin],
  outfile: 'dist/out.js',
});

